//vip.opstream14.com/20230109/29188_844e2209/index.m3u8"}]}],"time":"99 Phút","description":"<p>Cựu Mũ nồi xanh Louis Stevens trở về quê hương Miami sau khi hoàn thành nghĩa vụ quân sự ở Brazil, chỉ để biết rằng trường trung học cũ của anh đã trở thành nơi trú ẩn của các băng nhóm và buôn bán ma túy. Sau khi Stevens sử dụng kỹ năng capoeira của mình để đuổi một số kẻ buôn bán ma túy ra khỏi khuôn viên trường, Kerrigan, một trong những giáo viên cũ của Stevens, nhận thấy tác động của Stevens đối với học sinh. Kerrigan giao cho anh ta nhiệm vụ dạy Capoeira cho một số học sinh có nguy cơ kém nhất ở trường.</p>","tmdb":{"type":"movie","id":"15797","season":null,"vote_average":7,"vote_count":201},"modified":"2023-01-09T12:02:40.000Z"},{"id":"63bba0881c13612130dd6215","_id":"63bba0881c13612130dd6215","title":"Taras Bulba","origin_name":"Taras Bulba","slug":"taras-bulba","year":1962,"type":"single","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"},{"id":"620a2253e0fc277084dfd339","name":"Chiến Tranh","slug":"chien-tranh"},{"id":"620a2293e0fc277084dfd489","name":"Phiêu Lưu","slug":"phieu-luu"},{"id":"620f3d2b91fa4af90ab697fe","name":"Chính kịch","slug":"chinh-kich"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Taras Bulba 1962","link_embed":"https://vip.opstream14.com/share/23f38cc38c9291fec95487293bbed704","link_m3u8":"https://vip.opstream14.com/20230109/29189_0ea8ca6f/index.m3u8"}]}],"time":"119 Phút","description":"<p>Ukraine, thế kỷ 16. Trong khi người Ba Lan thống trị thảo nguyên Cossack, Andrei, con trai của Taras Bulba, một thủ lĩnh Cossack, phải lựa chọn giữa tình yêu dành cho gia đình và dân tộc của mình và tình yêu dành cho một p